#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>
#include <cuda_runtime.h>

#include "common.h"

extern "C" void setdevice(void);
extern "C" void checkCUDAError(const char *msg);

extern "C" __global__ void
findK_cuda(long height,
           knode *knodesD,
           long knodes_elem,
           record *recordsD,
           long *currKnodeD,
           long *offsetD,
           int *keysD,
           record *ansD);

#ifdef TIMING
static inline float tvdiff_ms(const struct timeval *end, const struct timeval *start) {
    return (float)((end->tv_sec - start->tv_sec) * 1000.0 +
                   (end->tv_usec - start->tv_usec) / 1000.0);
}
#endif

extern "C" void
kernel_gpu_cuda_wrapper(record *records,
                        long records_mem,
                        knode *knodes,
                        long knodes_elem,
                        long knodes_mem,
                        int order,
                        long maxheight,
                        int count,
                        long *currKnode,
                        long *offset,
                        int *keys,
                        record *ans)
{
#ifdef TIMING
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end, tv_mem_alloc_end, tv_close_start, tv_close_end;
    float init_time = 0.0f, mem_alloc_time = 0.0f, h2d_time = 0.0f;
    float kernel_time = 0.0f, d2h_time = 0.0f, close_time = 0.0f, total_time = 0.0f;
    struct timeval t1, t2;
    gettimeofday(&tv_total_start, NULL);
#endif

    int device_count = 0;
    cudaError_t cuda_err = cudaGetDeviceCount(&device_count);
    if (cuda_err != cudaSuccess) {
        printf("Cuda error: cudaGetDeviceCount: %s.\n", cudaGetErrorString(cuda_err));
        fflush(NULL);
        exit(EXIT_FAILURE);
    }

    printf("Platform: CUDA\n");
    printf("Device num: %u\n", (unsigned)device_count);

    setdevice();
    checkCUDAError("setdevice");

    int device = 0;
    cudaGetDevice(&device);
    checkCUDAError("cudaGetDevice");

    cudaDeviceProp prop;
    cudaGetDeviceProperties(&prop, device);
    checkCUDAError("cudaGetDeviceProperties");

    printf("Creating GPU Context\n");
    printf("Device: %s\n", prop.name);
    printf("-----OpenCL Compiler Output-----\n");
    printf("--------------------------------\n");

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    init_time = tvdiff_ms(&tv_init_end, &tv_total_start);
#endif

    record *recordsD = NULL;
    knode *knodesD = NULL;
    long *currKnodeD = NULL;
    long *offsetD = NULL;
    int *keysD = NULL;
    record *ansD = NULL;

    cudaMalloc((void **)&recordsD, (size_t)records_mem);
    checkCUDAError("cudaMalloc recordsD");

    cudaMalloc((void **)&knodesD, (size_t)knodes_mem);
    checkCUDAError("cudaMalloc knodesD");

    cudaMalloc((void **)&currKnodeD, (size_t)(count * sizeof(long)));
    checkCUDAError("cudaMalloc currKnodeD");

    cudaMalloc((void **)&offsetD, (size_t)(count * sizeof(long)));
    checkCUDAError("cudaMalloc offsetD");

    cudaMalloc((void **)&keysD, (size_t)(count * sizeof(long)));
    checkCUDAError("cudaMalloc keysD");

    cudaMalloc((void **)&ansD, (size_t)(count * sizeof(record)));
    checkCUDAError("cudaMalloc ansD");

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    mem_alloc_time = tvdiff_ms(&tv_mem_alloc_end, &tv_init_end);
#endif

#ifdef TIMING
    gettimeofday(&t1, NULL);
#endif
    cudaMemcpy(recordsD, records, (size_t)records_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy recordsD");
#ifdef TIMING
    gettimeofday(&t2, NULL);
    h2d_time += tvdiff_ms(&t2, &t1);
#endif

#ifdef TIMING
    gettimeofday(&t1, NULL);
#endif
    cudaMemcpy(knodesD, knodes, (size_t)knodes_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy knodesD");
#ifdef TIMING
    gettimeofday(&t2, NULL);
    h2d_time += tvdiff_ms(&t2, &t1);
#endif

#ifdef TIMING
    gettimeofday(&t1, NULL);
#endif
    cudaMemcpy(currKnodeD, currKnode, (size_t)(count * sizeof(long)), cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy currKnodeD");
#ifdef TIMING
    gettimeofday(&t2, NULL);
    h2d_time += tvdiff_ms(&t2, &t1);
#endif

#ifdef TIMING
    gettimeofday(&t1, NULL);
#endif
    cudaMemcpy(offsetD, offset, (size_t)(count * sizeof(long)), cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy offsetD");
#ifdef TIMING
    gettimeofday(&t2, NULL);
    h2d_time += tvdiff_ms(&t2, &t1);
#endif

#ifdef TIMING
    gettimeofday(&t1, NULL);
#endif
    cudaMemcpy(keysD, keys, (size_t)(count * sizeof(int)), cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy keysD");
#ifdef TIMING
    gettimeofday(&t2, NULL);
    h2d_time += tvdiff_ms(&t2, &t1);
#endif

#ifdef TIMING
    gettimeofday(&t1, NULL);
#endif
    cudaMemcpy(ansD, ans, (size_t)(count * sizeof(record)), cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy ansD");
#ifdef TIMING
    gettimeofday(&t2, NULL);
    h2d_time += tvdiff_ms(&t2, &t1);
#endif

    int local_work_size = order < 1024 ? order : 1024;
    int blocks = count;

    printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n",
           blocks, local_work_size);

#ifdef TIMING
    gettimeofday(&t1, NULL);
#endif
    findK_cuda<<<blocks, local_work_size>>>(maxheight,
                                            knodesD,
                                            knodes_elem,
                                            recordsD,
                                            currKnodeD,
                                            offsetD,
                                            keysD,
                                            ansD);
    checkCUDAError("findK_cuda launch");

    cudaDeviceSynchronize();
    checkCUDAError("findK_cuda sync");
#ifdef TIMING
    gettimeofday(&t2, NULL);
    kernel_time += tvdiff_ms(&t2, &t1);
#endif

#ifdef TIMING
    gettimeofday(&t1, NULL);
#endif
    cudaMemcpy(ans, ansD, (size_t)(count * sizeof(record)), cudaMemcpyDeviceToHost);
    checkCUDAError("cudaMemcpy ansD->ans");
#ifdef TIMING
    gettimeofday(&t2, NULL);
    d2h_time += tvdiff_ms(&t2, &t1);
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    cudaFree(recordsD);
    checkCUDAError("cudaFree recordsD");
    cudaFree(knodesD);
    checkCUDAError("cudaFree knodesD");
    cudaFree(currKnodeD);
    checkCUDAError("cudaFree currKnodeD");
    cudaFree(offsetD);
    checkCUDAError("cudaFree offsetD");
    cudaFree(keysD);
    checkCUDAError("cudaFree keysD");
    cudaFree(ansD);
    checkCUDAError("cudaFree ansD");

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    close_time += tvdiff_ms(&tv_close_end, &tv_close_start);
    tv_total_end = tv_close_end;
    total_time = tvdiff_ms(&tv_total_end, &tv_total_start);

    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

